// 定義所有分類及其難度
const categories = [
  { name: '入門心法', difficulty: 1, keywords: ['提示詞', '基礎', '入門', '新手', '基本操作'] },
  { name: '長輩友善', difficulty: 2, keywords: ['簡單', '長輩', '圖形', '手機', '日常'] },
  { name: '生活應用', difficulty: 2, keywords: ['旅遊', '社交', '生活', '實用', '日常'] },
  { name: '工作效率', difficulty: 3, keywords: ['工作', '效率', '辦公', '生產力', '報告'] },
  { name: '進階技巧', difficulty: 5, keywords: ['進階', 'API', '開發', '複雜', '人設'] }
];

// 根據日期循環選擇分類
const today = new Date();
const dayOfYear = Math.floor((today - new Date(today.getFullYear(), 0, 0)) / (1000 * 60 * 60 * 24));
const selectedIndex = dayOfYear % categories.length;

// 每天選擇 2-3 個分類生成內容
const selectedCategories = [categories[selectedIndex]];
if (dayOfYear % 2 === 0) {
  selectedCategories.push(categories[(selectedIndex + 1) % categories.length]);
}

return selectedCategories.map(cat => ({ json: cat }));

const searchResults = $input.all();
const resources = [];

searchResults.forEach(item => {
  if (item.json.webPages && item.json.webPages.value) {
    item.json.webPages.value.forEach((page, index) => {
      resources.push({
        title: page.name,
        url: page.url,
        snippet: page.snippet?.substring(0, 200) || ''
      });
    });
  }
});

return [{ json: { resources: resources.slice(0, 3) } }];

const response = $input.first().json.choices[0].message.content;
const article = JSON.parse(response);

// 生成結構化文章內容
const structuredContent = `
## ${article.title}

### 生活痛點
${article.pain_point}

### 應用場景
${article.scenario}

### AI 解決方案
${article.solution}

### 簡單實例
#### ❌ 錯誤示範
${article.example?.wrong || ''}

#### ✅ 正確用法
${article.example?.right || ''}

### 實作步驟
<ol>
<li>第一步：清楚定義你的目標</li>
<li>第二步：提供充分的背景資訊</li>
<li>第三步：使用具體、明確的指令</li>
<li>第四步：根據結果迭代優化</li>
</ol>

### 常見問題
${article.faq?.map(f => `#### Q: ${f.question}\nA: ${f.answer}`).join('\n\n')}

### 💡 學習挑戰
試試看用今天學到的技巧，解決一個你日常遇到的問題！

### 總結
${article.summary || ''}
`;

return [{
  json: {
    category: article.category_suggestion || '入門心法',
    title: article.title,
    summary: article.summary || '',
    content: structuredContent,
    read_time: `${Math.ceil(structuredContent.length / 500)} 分鐘`,
    is_published: false, // 預設為待審核狀態
    seo_title: article.seo_title || '',
    keywords: article.keywords || [],
    search_intent: article.search_intent || '',
    target_audience: article.target_audience || '',
    pain_point: article.pain_point || '',
    scenario: article.scenario || '',
    solution: article.solution || '',
    example: article.example || null,
    faq: article.faq || [],
    semantic_tags: article.semantic_tags || [],
    difficulty_level: article.difficulty_level || 1,
    ai_generated: true,
    created_at: new Date().toISOString(),
    published_at: new Date().toISOString()
  }
}];

const article = $input.first().json;
const issues = [];

// 檢查必填欄位
if (!article.title || article.title.length < 10) issues.push('標題太短');
if (!article.seo_title || article.seo_title.length < 20) issues.push('SEO標題太短');
if (!article.keywords || article.keywords.length < 3) issues.push('關鍵詞不足3個');
if (!article.faq || article.faq.length < 3) issues.push('FAQ不足3組');
if (!article.pain_point || article.pain_point.length < 20) issues.push('痛點描述太短');
if (!article.solution || article.solution.length < 50) issues.push('解決方案太短');

// 檢查內容長度
const contentLength = article.content?.length || 0;
if (contentLength < 500) issues.push('內容太短（<500字）');

// 檢查是否有遊戲化元素
if (!article.content.includes('挑戰') && !article.content.includes('學習')) {
  issues.push('缺少遊戲化元素');
}

const articleWithCheck = {
  ...article,
  quality_issues: issues,
  quality_score: Math.max(0, 100 - issues.length * 10),
  needs_review: issues.length > 0
};

return [{ json: articleWithCheck }];

